 def detectCycle(self, head: Optional[ListNode]) -> Optional[ListNode]:
 slow, fast = head, head
 while fast and fast.next:
 slow, fast = slow.next, fast.next.next
 if slow == fast:
 break
 else:
 return

 slow = head
 while slow != fast:
 slow, fast = slow.next, fast.next

